const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
return { json: { token: token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
const allowed = ['advisor','sub_agent','mga_principal','admin'];
if (allowed.indexOf(row.user_role) < 0) return { json: { _unauthorized: true, status: 403, error: 'Role not permitted' } };
return { json: { _ok: true, advisor_id: row.id || row.user_id, user_role: row.user_role } };

const raw = $input.item.json;
const rows = Array.isArray(raw) ? raw : (raw && raw.id ? [raw] : []);
const userRole = $('Check Role').item.json.user_role;
const pickField = (userRole === 'mga_principal') ? 'mga_commission' : 'advisor_commission';
// Monthly aggregation for chart.
const byMonth = {};
let totalEarnedCents = 0;
let totalPendingCents = 0;
let totalPaidCents = 0;
for (const r of rows) {
  const cents = parseInt(r[pickField]) || 0;
  totalEarnedCents += cents;
  if (r.payout_status === 'paid') totalPaidCents += cents;
  else if (r.payout_status === 'pending' || r.payout_status === 'processing' || r.payout_status === 'held') totalPendingCents += cents;
  if (r.created_at) {
    const month = String(r.created_at).slice(0, 7);
    byMonth[month] = (byMonth[month] || 0) + cents;
  }
}
const monthly = Object.keys(byMonth).sort().map(function (m) { return { month: m, cents: byMonth[m] }; });
return { json: { ok: true, vertical_id: 'insurance', commissions: rows, count: rows.length, totals: { earned_cents: totalEarnedCents, pending_cents: totalPendingCents, paid_cents: totalPaidCents }, monthly: monthly } };
